// Theorie-Trainer Reminder + Dokumente-Erinnerung
const schueler = $('Schueler laden').all();
const logItems = $('Reminder-Log laden').all();

// Cooldown: 7 Tage zwischen gleichen Reminder-Typen
const gesendetMap = {};
for (const item of logItems) {
  const key = `${item.json.Telefon}_${item.json.Typ}`;
  const datum = new Date(item.json.Gesendet_am);
  if (!gesendetMap[key] || datum > gesendetMap[key]) {
    gesendetMap[key] = datum;
  }
}

const now = new Date();
const results = [];
const COOLDOWN_TAGE = 7;

for (const item of schueler) {
  const data = item.json;

  const name = data.Name || data.Schueler || '';
  let telefon = data.Telefon || '';
  const status = (data.Status || '').toLowerCase();
  const theorieStatus = (data.Theorie_Status || data.theorie_status || '').toLowerCase();
  const dokuStatus = (data.Dokumente_Status || '').toLowerCase();
  const letzteTheorieAktivitaet = data.Letzte_Theorie_Aktivitaet || data.letzte_theorie || '';
  const fehlendeDokumente = data.Fehlende_Dokumente || data.fehlende_dokumente || '';

  // Inaktive/abgemeldete Schueler ueberspringen
  if (status === 'abgemeldet' || status === 'storniert' || status === 'bestanden') continue;
  if (!telefon || !name) continue;

  telefon = telefon.toString().replace(/[\s\-\/\(\)]/g, '');
  if (!telefon.startsWith('+')) {
    telefon = '+49' + telefon.replace(/^0/, '');
  }

  // --- THEORIE-TRAINER REMINDER ---
  // Nur wenn Schueler in Theorie-Phase ist und nicht schon bestanden hat
  if (theorieStatus !== 'bestanden' && theorieStatus !== 'abgeschlossen') {
    if (letzteTheorieAktivitaet) {
      let letzteAktiv;
      try { letzteAktiv = new Date(letzteTheorieAktivitaet); } catch(e) { letzteAktiv = null; }

      if (letzteAktiv && !isNaN(letzteAktiv.getTime())) {
        const tageSeitLetzterAktivitaet = Math.floor((now.getTime() - letzteAktiv.getTime()) / (1000 * 60 * 60 * 24));

        if (tageSeitLetzterAktivitaet >= 3) {
          const key = `${telefon}_theorie_reminder`;
          const letzterReminder = gesendetMap[key];
          const tageSeitReminder = letzterReminder ? Math.floor((now.getTime() - letzterReminder.getTime()) / (1000 * 60 * 60 * 24)) : 999;

          if (tageSeitReminder >= COOLDOWN_TAGE) {
            const motivationsTexte = [
              `Hallo ${name}! 📚\n\nSie haben ${tageSeitLetzterAktivitaet} Tage nicht im Theorie-Trainer geuebt. Bleiben Sie dran --- regelmaessiges Ueben ist der Schluessel zum Bestehen!\n\n🎯 Tagesziel: Nur 20 Fragen, das dauert ca. 10 Minuten.\n\n👉 Jetzt weiterlernen: ` + '{{ $env.WEBSITE_URL }}/theorie' + `\n\nSie schaffen das! 💪\n\nIhre Fahrschule 🚗`,
              `Hi ${name}! 👋\n\nKleine Erinnerung: Der Theorie-Trainer wartet auf Sie! Letzte Aktivitaet war vor ${tageSeitLetzterAktivitaet} Tagen.\n\n💡 Wussten Sie? Schueler die taeglich ueben, bestehen die Pruefung beim ersten Versuch 40% haeufiger!\n\n📱 ` + '{{ $env.WEBSITE_URL }}/theorie' + `\n\nViel Erfolg! 🍀\n\nIhre Fahrschule`
            ];

            results.push({
              json: {
                schuelerName: name,
                schuelerTelefon: telefon,
                typ: 'theorie_reminder',
                nachricht: motivationsTexte[Math.floor(Math.random() * motivationsTexte.length)],
                tageSeitAktivitaet: tageSeitLetzterAktivitaet
              }
            });
          }
        }
      }
    }
  }

  // --- DOKUMENTE-ERINNERUNG ---
  if (dokuStatus !== 'komplett' && dokuStatus !== 'vollstaendig' && fehlendeDokumente) {
    const key = `${telefon}_dokumente_reminder`;
    const letzterReminder = gesendetMap[key];
    const tageSeitReminder = letzterReminder ? Math.floor((now.getTime() - letzterReminder.getTime()) / (1000 * 60 * 60 * 24)) : 999;

    if (tageSeitReminder >= COOLDOWN_TAGE) {
      results.push({
        json: {
          schuelerName: name,
          schuelerTelefon: telefon,
          typ: 'dokumente_reminder',
          nachricht: `Hallo ${name},\n\nkurze Erinnerung: Uns fehlen noch folgende Unterlagen von Ihnen:\n\n${fehlendeDokumente.split(',').map(d => '📎 ' + d.trim()).join('\n')}\n\nBitte reichen Sie diese zeitnah ein, damit wir Ihren Antrag beim TUeV stellen koennen.\n\n💡 Sie koennen die Dokumente einfach als Foto per WhatsApp schicken!\n\nIhre Fahrschule`,
          fehlendeDokumente
        }
      });
    }
  }
}

return results.length > 0 ? results : [{ json: { skip: true } }];
